#include <stdio.h>

int main() {
    // Déclaration et initialisation du tableau
    float notesEleves[20] = {12, 15, 8, 10, 16, 14, 9, 11, 13, 17, 
                              5, 18, 7, 10, 12, 14, 15, 9, 11, 13};
    int i, compteur = 0;

    // Parcours du tableau pour compter les notes > 10
    for (i = 0; i < 20; i++) {
        if (notesEleves[i] > 10) {
            compteur++;
        }
    }

    // Affichage du résultat
    printf("Nombre d'élèves ayant une note > 10 : %d\n", compteur);

    return 0;
}
```

Remarque : En C, l'indice du premier élément est 0, donc la boucle va de 0 à 19 (inclus).
